// Make view-level transitivity explicit so z3 can chain the two ensures.
assert(
    (optional_value_view(ov) == optional_value_view(r1)
     && optional_value_view(ov) == optional_value_view(r2))
    ==> optional_value_view(r1) == optional_value_view(r2)
);

// Case-split on `ov` to expose r1 / r2's shape, then close the
// Seq-level gap with pointwise equality + extensionality (`=~=`).
assert(
    (optional_value_view(ov) == optional_value_view(r1)
     && optional_value_view(ov) == optional_value_view(r2))
    ==> (
        match ov {
            Some(_) => r1 is Some && r2 is Some && r1->Some_0@ =~= r2->Some_0@,
            None => r1 is None && r2 is None,
        }
    )
) by {
    if optional_value_view(ov) == optional_value_view(r1)
        && optional_value_view(ov) == optional_value_view(r2)
    {
        match ov {
            Some(_) => {
                assert(r1 is Some);
                assert(r2 is Some);
                assert forall|i: int|
                    0 <= i < r1->Some_0@.len() implies r1->Some_0@[i] == r2->Some_0@[i]
                by {
                    assert(r1->Some_0@[i] == ov->Some_0@[i]);
                    assert(r2->Some_0@[i] == ov->Some_0@[i]);
                };
                assert(r1->Some_0@ =~= r2->Some_0@);
            }
            None => {
                assert(r1 is None);
                assert(r2 is None);
            }
        }
    }
}
